class InventoryManager:
    """Thread-safe inventory manager using asyncio locks for concurrent access."""

    def __init__(self):
        self._player_locks: Dict[str, asyncio.Lock] = {}
        self._trade_lock = asyncio.Lock()
        self._global_item_lock = asyncio.Lock()

    def _get_player_lock(self, player_id: str) -> asyncio.Lock:
        if player_id not in self._player_locks:
            self._player_locks[player_id] = asyncio.Lock()
        return self._player_locks[player_id]

    async def add_item_to_inventory(self, player: Player, item: Item) -> bool:
        lock = self._get_player_lock(player.player_id)
        async with lock:
            if len(player.inventory) >= player.max_inventory_size:
                return False
            item.owner_id = player.player_id
            player.inventory[item.item_id] = item
            return True

    async def remove_item_from_inventory(self, player: Player, item_id: str) -> Optional[Item]:
        lock = self._get_player_lock(player.player_id)
        async with lock:
            item = player.inventory.pop(item_id, None)
            if item:
                item.owner_id = None
            return item

    async def transfer_item(self, from_player: Player, to_player: Player, item_id: str) -> bool:
        lock1_id = min(from_player.player_id, to_player.player_id)
        lock2_id = max(from_player.player_id, to_player.player_id)
        lock1 = self._get_player_lock(lock1_id)
        lock2 = self._get_player_lock(lock2_id)

        async with lock1:
            async with lock2:
                if item_id not in from_player.inventory:
                    return False
                item = from_player.inventory[item_id]
                if not item.tradeable:
                    return False
                if len(to_player.inventory) >= to_player.max_inventory_size:
                    return False
                del from_player.inventory[item_id]
                item.owner_id = to_player.player_id
                to_player.inventory[item_id] = item
                return True

    async def transfer_gold(self, from_player: Player, to_player: Player, amount: int) -> bool:
        lock1_id = min(from_player.player_id, to_player.player_id)
        lock2_id = max(from_player.player_id, to_player.player_id)
        lock1 = self._get_player_lock(lock1_id)
        lock2 = self._get_player_lock(lock2_id)

        async with lock1:
            async with lock2:
                if from_player.gold < amount or amount < 0:
                    return False
                from_player.gold -= amount
                to_player.gold += amount
                return True

    async def execute_trade(self, trade: TradeOffer, players: Dict[str, Player]) -> bool:
        """Execute a confirmed trade atomically."""
        async with self._trade_lock:
            initiator = players.get(trade.initiator_id)
            receiver = players.get(trade.receiver_id)

            if not initiator or not receiver:
                return False

            lock1_id = min(initiator.player_id, receiver.player_id)
            lock2_id = max(initiator.player_id, receiver.player_id)
            lock1 = self._get_player_lock(lock1_id)
            lock2 = self._get_player_lock(lock2_id)

            async with lock1:
                async with lock2:
                    # Validate all items still exist and are owned correctly
                    for item_id in trade.initiator_items:
                        if item_id not in initiator.inventory:
                            return False
                        if not initiator.inventory[item_id].tradeable:
                            return False

                    for item_id in trade.receiver_items:
                        if item_id not in receiver.inventory:
                            return False
                        if not receiver.inventory[item_id].tradeable:
                            return False

                    # Validate gold
                    if initiator.gold < trade.initiator_gold:
                        return False
                    if receiver.gold < trade.receiver_gold:
                        return False

                    # Validate inventory space
                    initiator_net = len(trade.receiver_items) - len(trade.initiator_items)
                    receiver_net = len(trade.initiator_items) - len(trade.receiver_items)

                    if len(initiator.inventory) + initiator_net > initiator.max_inventory_size:
                        return False
                    if len(receiver.inventory) + receiver_net > receiver.max_inventory_size:
                        return False

                    # Execute: transfer items from initiator to receiver
                    for item_id in trade.initiator_items:
                        item = initiator.inventory.pop(item_id)
                        item.owner_id = receiver.player_id
                        receiver.inventory[item_id] = item

                    # Execute: transfer items from receiver to initiator
                    for item_id in trade.receiver_items:
                        item = receiver.inventory.pop(item_id)
                        item.owner_id = initiator.player_id
                        initiator.inventory[item_id] = item

                    # Execute: transfer gold
                    if trade.initiator_gold > 0:
                        initiator.gold -= trade.initiator_gold
                        receiver.gold += trade.initiator_gold

                    if trade.receiver_gold > 0:
                        receiver.gold -= trade.receiver_gold
                        initiator.gold += trade.receiver_gold

                    return True


class GameServer:
    def __init__(self, host: str = "localhost", port: int = 8765):
        self.host = host
        self.port = port
        self.players: Dict[str, Player] = {}
        self.connections: Dict[str, websockets.WebSocketServerProtocol] = {}
        self.username_to_id: Dict[str, str] = {}
        self.trades: Dict[str, TradeOffer] = {}
        self.inventory_manager = InventoryManager()
        self.item_templates = self._create_item_templates()

    def _create_item_templates(self) -> Dict[str, dict]:
        return {
            "iron_sword": {"name": "Iron Sword", "rarity": ItemRarity.COMMON, "base_value": 50},
            "steel_shield": {"name": "Steel Shield", "rarity": ItemRarity.COMMON, "base_value": 75},
            "health_potion": {"name": "Health Potion", "rarity": ItemRarity.COMMON, "base_value": 25},
            "mana_potion": {"name": "Mana Potion", "rarity": ItemRarity.COMMON, "base_value": 30},
            "dragon_blade": {"name": "Dragon Blade", "rarity": ItemRarity.RARE, "base_value": 500},
            "phoenix_staff": {"name": "Phoenix Staff", "rarity": ItemRarity.EPIC, "base_value": 1200},
            "crown_of_ages": {"name": "Crown of Ages", "rarity": ItemRarity.LEGENDARY, "base_value": 5000},
            "shadow_cloak": {"name": "Shadow Cloak", "rarity": ItemRarity.UNCOMMON, "base_value": 200},
            "enchanted_ring": {"name": "Enchanted Ring", "rarity": ItemRarity.RARE, "base_value": 350},
            "soul_gem": {"name": "Soul Gem", "rarity": ItemRarity.EPIC, "base_value": 800, "tradeable": False},
        }

    def _create_item(self, template_key: str) -> Optional[Item]:
        template = self.item_templates.get(template_key)
        if not template:
            return None
        return Item(
            item_id=str(uuid.uuid4()),
            name=template["name"],
            rarity=template["rarity"],
            base_value=template["base_value"],
            tradeable=template.get("tradeable", True),
        )

    async def _send_to_player(self, player_id: str, message: dict):
        ws = self.connections.get(player_id)
        if ws:
            try:
                await ws.send(json.dumps(message))
            except websockets.exceptions.ConnectionClosed:
                logger.warning(f"Connection closed for player {player_id}")

    async def _broadcast(self, message: dict, exclude: Optional[Set[str]] = None):
        exclude = exclude or set()
        tasks = []
        for pid, ws in self.connections.items():
            if pid not in exclude:
                tasks.append(self._send_to_player(pid, message))
        if tasks:
            await asyncio.gather(*tasks, return_exceptions=True)

    async def handle_login(self, websocket, data: dict) -> Optional[str]:
        username = data.get("username", "").strip()
        if not username:
            await websocket.send(json.dumps({
                "type": "error",
                "message": "Username is required"
            }))
            return None

        if username in self.username_to_id:
            existing_id = self.username_to_id[username]
            if existing_id in self.connections:
                await websocket.send(json.dumps({
                    "type": "error",
                    "message": "Username already connected"
                }))
                return None
            # Reconnect
            player = self.players[existing_id]
            player.websocket = websocket
            self.connections[existing_id] = websocket
            logger.info(f"Player {username} reconnected as {existing_id}")
            await websocket.send(json.dumps({
                "type": "login_success",
                "player": player.to_dict()
            }))
            await self._broadcast({
                "type": "player_online",
                "player_id": existing_id,
                "username": username
            }, exclude={existing_id})
            return existing_id

        player_id = str(uuid.uuid4())
        player = Player(
            player_id=player_id,
            username=username,
            websocket=websocket,
        )

        # Give starter items
        starter_items = ["iron_sword", "health_potion", "health_potion", "mana_potion"]
        for template_key in starter_items:
            item = self._create_item(template_key)
            if item:
                await self.inventory_manager.add_item_to_inventory(player, item)

        self.players[player_id] = player
        self.connections[player_id] = websocket
        self.username_to_id[username] = player_id

        logger.info(f"Player {username} logged in as {player_id}")

        await websocket.send(json.dumps({
            "type": "login_success",
            "player": player.to_dict()
        }))

        await self._broadcast({
            "type": "player_online",
            "player_id": player_id,
            "username": username
        }, exclude={player_id})

        return player_id

    async def handle_get_inventory(self, player_id: str):
        player = self.players.get(player_id)
        if not player:
            return

        await self._send_to_player(player_id, {
            "type": "inventory_update",
            "inventory": {k: v.to_dict() for k, v in player.inventory.items()},
            "gold": player.gold,
        })

    async def handle_spawn_item(self, player_id: str, data: dict):
        """Debug/admin command to spawn items."""
        player = self.players.get(player_id)
        if not player:
            return

        template_key = data.get("template_key")
        item = self._create_item(template_key)
        if not item:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": f"Unknown item template: {template_key}"
            })
            return

        success = await self.inventory_manager.add_item_to_inventory(player, item)
        if success:
            await self._send_to_player(player_id, {
                "type": "item_acquired",
                "item": item.to_dict(),
                "message": f"Acquired {item.name}!"
            })
            await self.handle_get_inventory(player_id)
        else:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Inventory is full!"
            })

    async def handle_drop_item(self, player_id: str, data: dict):
        player = self.players.get(player_id)
        if not player:
            return

        item_id = data.get("item_id")
        item = await self.inventory_manager.remove_item_from_inventory(player, item_id)
        if item:
            await self._send_to_player(player_id, {
                "type": "item_dropped",
                "item": item.to_dict(),
                "message": f"Dropped {item.name}"
            })
            await self.handle_get_inventory(player_id)
        else:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Item not found in inventory"
            })

    async def handle_direct_transfer(self, player_id: str, data: dict):
        """Direct item transfer (gift) between players."""
        from_player = self.players.get(player_id)
        to_player_id = data.get("to_player_id")
        to_player = self.players.get(to_player_id)
        item_id = data.get("item_id")

        if not from_player or not to_player:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Player not found"
            })
            return

        if to_player_id not in self.connections:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Target player is offline"
            })
            return

        success = await self.inventory_manager.transfer_item(from_player, to_player, item_id)
        if success:
            item = to_player.inventory[item_id]
            await self._send_to_player(player_id, {
                "type": "item_sent",
                "item": item.to_dict(),
                "to_player": to_player.username,
                "message": f"Sent {item.name} to {to_player.username}"
            })
            await self._send_to_player(to_player_id, {
                "type": "item_received",
                "item": item.to_dict(),
                "from_player": from_player.username,
                "message": f"Received {item.name} from {from_player.username}"
            })
            await self.handle_get_inventory(player_id)
            await self.handle_get_inventory(to_player_id)
        else:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Transfer failed. Item may not exist, not be tradeable, or target inventory is full."
            })

    async def handle_trade_initiate(self, player_id: str, data: dict):
        """Initiate a trade with another player."""
        initiator = self.players.get(player_id)
        receiver_id = data.get("receiver_id")
        receiver = self.players.get(receiver_id)

        if not initiator or not receiver:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Player not found"
            })
            return

        if receiver_id not in self.connections:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Target player is offline"
            })
            return

        if initiator.active_trade_id:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "You are already in a trade"
            })
            return

        if receiver.active_trade_id:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": f"{receiver.username} is already in a trade"
            })
            return

        trade_id = str(uuid.uuid4())
        trade = TradeOffer(
            trade_id=trade_id,
            initiator_id=player_id,
            receiver_id=receiver_id,
        )

        self.trades[trade_id] = trade
        initiator.active_trade_id = trade_id
        receiver.active_trade_id = trade_id

        await self._send_to_player(player_id, {
            "type": "trade_initiated",
            "trade": trade.to_dict(),
            "message": f"Trade request sent to {receiver.username}"
        })

        await self._send_to_player(receiver_id, {
            "type": "trade_request",
            "trade": trade.to_dict(),
            "from_player": initiator.username,
            "message": f"{initiator.username} wants to trade with you"
        })

    async def handle_trade_accept(self, player_id: str, data: dict):
        """Accept an incoming trade request."""
        trade_id = data.get("trade_id")
        trade = self.trades.get(trade_id)

        if not trade or trade.receiver_id != player_id:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Invalid trade"
            })
            return

        if trade.status != "pending":
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Trade is no longer pending"
            })
            return

        trade.status = "accepted"

        await self._send_to_player(trade.initiator_id, {
            "type": "trade_accepted",
            "trade": trade.to_dict(),
            "message": "Trade accepted! Add items to trade."
        })

        await self._send_to_player(trade.receiver_id, {
            "type": "trade_accepted",
            "trade": trade.to_dict(),
            "message": "Trade accepted! Add items to trade."
        })

    async def handle_trade_decline(self, player_id: str, data: dict):
        """Decline a trade request."""
        trade_id = data.get("trade_id")
        trade = self.trades.get(trade_id)

        if not trade:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Invalid trade"
            })
            return

        if player_id not in (trade.initiator_id, trade.receiver_id):
            return

        await self._cleanup_trade(trade, "declined")

    async def handle_trade_add_item(self, player_id: str, data: dict):
        """Add an item to the current trade."""
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "No active trade"
            })
            return

        trade = self.trades.get(player.active_trade_id)
        if not trade or trade.status != "accepted":
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Trade is not in accepted state"
            })
            return

        item_id = data.get("item_id")
        if item_id not in player.inventory:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Item not found in inventory"
            })
            return

        item = player.inventory[item_id]
        if not item.tradeable:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": f"{item.name} is not tradeable"
            })
            return

        # Reset confirmations when trade contents change
        trade.initiator_confirmed = False
        trade.receiver_confirmed = False

        if player_id == trade.initiator_id:
            if item_id not in trade.initiator_items:
                trade.initiator_items.append(item_id)
        elif player_id == trade.receiver_id:
            if item_id not in trade.receiver_items:
                trade.receiver_items.append(item_id)

        await self._send_trade_update(trade)

    async def handle_trade_remove_item(self, player_id: str, data: dict):
        """Remove an item from the current trade."""
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "No active trade"
            })
            return

        trade = self.trades.get(player.active_trade_id)
        if not trade or trade.status != "accepted":
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Trade is not in accepted state"
            })
            return

        item_id = data.get("item_id")

        # Reset confirmations when trade contents change
        trade.initiator_confirmed = False
        trade.receiver_confirmed = False

        if player_id == trade.initiator_id:
            if item_id in trade.initiator_items:
                trade.initiator_items.remove(item_id)
        elif player_id == trade.receiver_id:
            if item_id in trade.receiver_items:
                trade.receiver_items.remove(item_id)

        await self._send_trade_update(trade)

    async def handle_trade_set_gold(self, player_id: str, data: dict):
        """Set gold amount in the current trade."""
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "No active trade"
            })
            return

        trade = self.trades.get(player.active_trade_id)
        if not trade or trade.status != "accepted":
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Trade is not in accepted state"
            })
            return

        amount = data.get("gold", 0)
        if not isinstance(amount, int) or amount < 0:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Invalid gold amount"
            })
            return

        if amount > player.gold:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Not enough gold"
            })
            return

        # Reset confirmations
        trade.initiator_confirmed = False
        trade.receiver_confirmed = False

        if player_id == trade.initiator_id:
            trade.initiator_gold = amount
        elif player_id == trade.receiver_id:
            trade.receiver_gold = amount

        await self._send_trade_update(trade)

    async def handle_trade_confirm(self, player_id: str, data: dict):
        """Confirm the trade. When both confirm, execute."""
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "No active trade"
            })
            return

        trade = self.trades.get(player.active_trade_id)
        if not trade or trade.status != "accepted":
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Trade is not in accepted state"
            })
            return

        if player_id == trade.initiator_id:
            trade.initiator_confirmed = True
        elif player_id == trade.receiver_id:
            trade.receiver_confirmed = True

        await self._send_trade_update(trade)

        # If both confirmed, execute the trade
        if trade.initiator_confirmed and trade.receiver_confirmed:
            success = await self.inventory_manager.execute_trade(trade, self.players)
            if success:
                trade.status = "completed"
                initiator = self.players.get(trade.initiator_id)
                receiver = self.players.get(trade.receiver_id)

                await self._send_to_player(trade.initiator_id, {
                    "type": "trade_completed",
                    "trade": trade.to_dict(),
                    "message": f"Trade with {receiver.username if receiver else 'unknown'} completed!"
                })
                await self._send_to_player(trade.receiver_id, {
                    "type": "trade_completed",
                    "trade": trade.to_dict(),
                    "message": f"Trade with {initiator.username if initiator else 'unknown'} completed!"
                })

                # Cleanup
                if initiator:
                    initiator.active_trade_id = None
                    await self.handle_get_inventory(trade.initiator_id)
                if receiver:
                    receiver.active_trade_id = None
                    await self.handle_get_inventory(trade.receiver_id)

                del self.trades[trade.trade_id]

                logger.info(f"Trade {trade.trade_id} completed between {trade.initiator_id} and {trade.receiver_id}")
            else:
                await self._send_to_player(trade.initiator_id, {
                    "type": "error",
                    "message": "Trade execution failed. Items may have changed."
                })
                await self._send_to_player(trade.receiver_id, {
                    "type": "error",
                    "message": "Trade execution failed. Items may have changed."
                })
                trade.initiator_confirmed = False
                trade.receiver_confirmed = False
                await self._send_trade_update(trade)

    async def handle_trade_cancel(self, player_id: str, data: dict):
        """Cancel the current trade."""
        player = self.players.get(player_id)
        if not player or not player.active_trade_id:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "No active trade"
            })
            return

        trade = self.trades.get(player.active_trade_id)
        if not trade:
            player.active_trade_id = None
            return

        await self._cleanup_trade(trade, "cancelled")

    async def handle_list_players(self, player_id: str):
        """List all online players."""
        online_players = []
        for pid, ws in self.connections.items():
            if pid != player_id:
                p = self.players.get(pid)
                if p:
                    online_players.append({
                        "player_id": pid,
                        "username": p.username,
                        "in_trade": p.active_trade_id is not None,
                    })

        await self._send_to_player(player_id, {
            "type": "player_list",
            "players": online_players,
        })

    async def handle_inspect_player(self, player_id: str, data: dict):
        """Inspect another player's public inventory."""
        target_id = data.get("target_id")
        target = self.players.get(target_id)

        if not target:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Player not found"
            })
            return

        public_inventory = {}
        for k, v in target.inventory.items():
            public_inventory[k] = {
                "item_id": v.item_id,
                "name": v.name,
                "rarity": v.rarity.value,
                "tradeable": v.tradeable,
            }

        await self._send_to_player(player_id, {
            "type": "player_inspect",
            "target_id": target_id,
            "target_username": target.username,
            "inventory": public_inventory,
        })

    async def _send_trade_update(self, trade: TradeOffer):
        """Send trade update to both parties with item details."""
        initiator = self.players.get(trade.initiator_id)
        receiver = self.players.get(trade.receiver_id)

        initiator_item_details = []
        for item_id in trade.initiator_items:
            if initiator and item_id in initiator.inventory:
                initiator_item_details.append(initiator.inventory[item_id].to_dict())

        receiver_item_details = []
        for item_id in trade.receiver_items:
            if receiver and item_id in receiver.inventory:
                receiver_item_details.append(receiver.inventory[item_id].to_dict())

        update = {
            "type": "trade_update",
            "trade": trade.to_dict(),
            "initiator_item_details": initiator_item_details,
            "receiver_item_details": receiver_item_details,
        }

        await self._send_to_player(trade.initiator_id, update)
        await self._send_to_player(trade.receiver_id, update)

    async def _cleanup_trade(self, trade: TradeOffer, status: str):
        """Clean up a trade and notify both parties."""
        trade.status = status

        initiator = self.players.get(trade.initiator_id)
        receiver = self.players.get(trade.receiver_id)

        if initiator:
            initiator.active_trade_id = None
        if receiver:
            receiver.active_trade_id = None

        await self._send_to_player(trade.initiator_id, {
            "type": f"trade_{status}",
            "trade_id": trade.trade_id,
            "message": f"Trade {status}"
        })

        await self._send_to_player(trade.receiver_id, {
            "type": f"trade_{status}",
            "trade_id": trade.trade_id,
            "message": f"Trade {status}"
        })

        if trade.trade_id in self.trades:
            del self.trades[trade.trade_id]

    async def _cleanup_stale_trades(self):
        """Periodically clean up stale trades."""
        while True:
            await asyncio.sleep(60)
            now = time.time()
            stale_trades = [
                t for t in self.trades.values()
                if now - t.created_at > 300  # 5 minute timeout
            ]
            for trade in stale_trades:
                logger.info(f"Cleaning up stale trade {trade.trade_id}")
                await self._cleanup_trade(trade, "cancelled")

    async def handle_message(self, player_id: str, message: str):
        """Route incoming messages to appropriate handlers."""
        try:
            data = json.loads(message)
        except json.JSONDecodeError:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": "Invalid JSON"
            })
            return

        msg_type = data.get("type")

        handlers = {
            "get_inventory": lambda: self.handle_get_inventory(player_id),
            "spawn_item": lambda: self.handle_spawn_item(player_id, data),
            "drop_item": lambda: self.handle_drop_item(player_id, data),
            "direct_transfer": lambda: self.handle_direct_transfer(player_id, data),
            "trade_initiate": lambda: self.handle_trade_initiate(player_id, data),
            "trade_accept": lambda: self.handle_trade_accept(player_id, data),
            "trade_decline": lambda: self.handle_trade_decline(player_id, data),
            "trade_add_item": lambda: self.handle_trade_add_item(player_id, data),
            "trade_remove_item": lambda: self.handle_trade_remove_item(player_id, data),
            "trade_set_gold": lambda: self.handle_trade_set_gold(player_id, data),
            "trade_confirm": lambda: self.handle_trade_confirm(player_id, data),
            "trade_cancel": lambda: self.handle_trade_cancel(player_id, data),
            "list_players": lambda: self.handle_list_players(player_id),
            "inspect_player": lambda: self.handle_inspect_player(player_id, data),
        }

        handler = handlers.get(msg_type)
        if handler:
            await handler()
        else:
            await self._send_to_player(player_id, {
                "type": "error",
                "message": f"Unknown message type: {msg_type}"
            })

    async def handle_connection(self, websocket, path=None):
        """Handle a new websocket connection."""
        player_id = None
        try:
            # Wait for login message
            login_msg = await asyncio.wait_for(websocket.recv(), timeout=30.0)
            login_data = json.loads(login_msg)

            if login_data.get("type") != "login":
                await websocket.send(json.dumps({
                    "type": "error",
                    "message": "First message must be a login"
                }))
                return

            player_id = await self.handle_login(websocket, login_data)
            if not player_id:
                return

            # Main message loop
            async for message in websocket:
                try:
                    await self.handle_message(player_id, message)
                except Exception as e:
                    logger.error(f"Error handling message from {player_id}: {e}", exc_info=True)
                    await self._send_to_player(player_id, {
                        "type": "error",
                        "message": "Internal server error"
                    })

        except asyncio.TimeoutError:
            logger.info("Connection timed out waiting for login")
        except websockets.exceptions.ConnectionClosed:
            logger.info(f"Connection closed for player {player_id}")
        except Exception as e:
            logger.error(f"Unexpected error: {e}", exc_info=True)
        finally:
            if player_id:
                # Clean up active trade
                player = self.players.get(player_id)
                if player and player.active_trade_id:
                    trade = self.trades.get(player.active_trade_id)
                    if trade:
                        await self._cleanup_trade(trade, "cancelled")

                # Remove connection but keep player data for reconnection
                if player_id in self.connections:
                    del self.connections[player_id]

                await self._broadcast({
                    "type": "player_offline",
                    "player_id": player_id,
                    "username": player.username if player else "unknown"
                })

                logger.info(f"Player {player_id} disconnected")

    async def start(self):
        """Start the game server."""
        logger.info(f"Starting MMO Game Server on ws://{self.host}:{self.port}")

        # Start background tasks
        stale_trade_task = asyncio.create_task(self._cleanup_stale_trades())

        try:
            async with websockets.serve(
                self.handle_connection,
                self.host,
                self.port,
                ping_interval=20,
                ping_timeout=20,
                max_size=2**16,
            ):
                logger.info("Server is running. Press Ctrl+C to stop.")
                await asyncio.Future()  # Run forever
        except asyncio.CancelledError:
            pass
        finally:
            stale_trade_task.cancel()
            try:
                await stale_trade_task
            except asyncio.CancelledError:
                pass
            logger.info("Server stopped.")


async def demo_client(username: str, actions: list):
    """Demo client for testing the server."""
    uri = "ws://localhost:8765"
    async with websockets.connect(uri) as ws:
        # Login
        await ws.send(json.dumps({"type": "login", "username": username}))
        response = json.loads(await ws.recv())
        print(f"[{username}] {response['type']}: {response.get('message', '')}")

        if response["type"] == "login_success":
            player_data = response["player"]
            print(f"[{username}] Player ID: {player_data['player_id']}")
            print(f"[{username}] Gold: {player_data['gold']}")
            print(f"[{username}] Items: {len(player_data['inventory'])}")

        for action in actions:
            await ws.send(json.dumps(action))
            try:
                response = json.loads(await asyncio.wait_for(ws.recv(), timeout=5.0))
                print(f"[{username}] {response['type']}: {response.get('message', '')}")
            except asyncio.TimeoutError:
                print(f"[{username}] Timeout waiting for response")

        # Listen for additional messages briefly
        try:
            while True:
                response = json.loads(await asyncio.wait_for(ws.recv(), timeout=3.0))
                print(f"[{username}] {response['type']}: {response.get('message', '')}")
        except asyncio.TimeoutError:
            pass


async def run_demo():
    """Run a demo with multiple clients."""
    server = GameServer()
    server_task = asyncio.create_task(server.start())

    await asyncio.sleep(1)  # Wait for server to start

    try:
        # Client 1: Alice
        alice_actions = [
            {"type": "get_inventory"},
            {"type": "spawn_item", "template_key": "dragon_blade"},
            {"type": "list_players"},
        ]

        # Client 2: Bob
        bob_actions = [
            {"type": "get_inventory"},
            {"type": "spawn_item", "template_key": "phoenix_staff"},
            {"type": "list_players"},
        ]

        await asyncio.gather(
            demo_client("Alice", alice_actions),
            demo_client("Bob", bob_actions),
        )

    finally:
        server_task.cancel()
        try:
            await server_task
        except asyncio.CancelledError:
            pass


if __name__ == "__main__":
    import sys

    if len(sys.argv) > 1 and sys.argv[1] == "demo":
        asyncio.run(run_demo())
    else:
        server = GameServer()
        try:
            asyncio.run(server.start())
        except KeyboardInterrupt:
            logger.info("Server shutdown requested")